from typing import Dict

def main() -> None:
    state = {
        'input_value': 0,
        'result': 0
    }
    perform_calculation(state)
    display_result(state)

def perform_calculation(state: Dict[str, int]) -> None:
    state['result'] = state['input_value'] * 2

def display_result(state: Dict[str, int]) -> None:
    print(f"Result: {state['result']}")

if __name__ == "__main__":
    main()
